import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const y=JSON.parse('{"title":"チャレンジステージ","description":"","frontmatter":{},"headers":[],"relativePath":"ja/stages/challenge.md","filePath":"ja/stages/challenge.md","lastUpdated":1775394001000}'),i={name:"ja/stages/challenge.md"};function n(r,t,s,h,g,x){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="チャレンジステージ" tabindex="-1">チャレンジステージ <a class="header-anchor" href="#チャレンジステージ" aria-label="Permalink to &quot;チャレンジステージ&quot;">​</a></h1><p>チャレンジステージは高難度の常設ステージです。高レアリティの密契・刻印・特殊素材がドロップします。</p><h2 id="ステージ一覧" tabindex="-1">ステージ一覧 <a class="header-anchor" href="#ステージ一覧" aria-label="Permalink to &quot;ステージ一覧&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">ステージ</th><th style="text-align:center;">タイプ</th><th style="text-align:center;">リセット</th><th style="text-align:left;">ドロップ</th><th style="text-align:left;">解放条件</th></tr></thead><tbody><tr><td style="text-align:left;">融災禁区 (Erosion Disaster Zone)</td><td style="text-align:center;">高難度チャレンジ</td><td style="text-align:center;">2週間（木曜15:00）</td><td style="text-align:left;">黒色貢物、原初霊核、霊核碎片</td><td style="text-align:left;">メインステージ4-3通関</td></tr><tr><td style="text-align:left;">幻夢深潜 (Phantasmal Dive)</td><td style="text-align:center;">Roguelikeランキング</td><td style="text-align:center;">毎週</td><td style="text-align:left;">融蝕之珠（D-Jewels）、銀芯</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;">相位対弈 (Phase Chess)</td><td style="text-align:center;">PVPランキング</td><td style="text-align:center;">毎週</td><td style="text-align:left;">演習徽章、蔷薇金券</td><td style="text-align:left;">メインステージ3-2通関</td></tr><tr><td style="text-align:left;">無光秘境 (Lightless Realm)</td><td style="text-align:center;">昇星チャレンジ</td><td style="text-align:center;">—</td><td style="text-align:left;">無光幣</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;">界域異効区 (D-Effect Zone)</td><td style="text-align:center;">チャレンジ副本</td><td style="text-align:center;">—</td><td style="text-align:left;">無光幣</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;">秘術統御 (Arcane Dominion)</td><td style="text-align:center;">チャレンジ副本</td><td style="text-align:center;">—</td><td style="text-align:left;">調査徽章</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;">天外之下 (Under the Outer Sky)</td><td style="text-align:center;">新副本</td><td style="text-align:center;">—</td><td style="text-align:left;">—</td><td style="text-align:left;">v2.0+</td></tr></tbody></table><h2 id="融災禁区-詳細" tabindex="-1">融災禁区（詳細） <a class="header-anchor" href="#融災禁区-詳細" aria-label="Permalink to &quot;融災禁区（詳細）&quot;">​</a></h2><p>多チーム終局コンテンツ。同一覚醒体・運命の輪・鍵令をチーム間で重複使用不可。</p><h3 id="アラートレベル" tabindex="-1">アラートレベル <a class="header-anchor" href="#アラートレベル" aria-label="Permalink to &quot;アラートレベル&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">レベル</th><th style="text-align:left;">訓練値</th><th style="text-align:center;">敵レベル</th><th style="text-align:left;">備考</th></tr></thead><tbody><tr><td style="text-align:center;">I</td><td style="text-align:left;">50/55/60/65/70</td><td style="text-align:center;">50-58</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:center;">II</td><td style="text-align:left;">55/60/65/70/75</td><td style="text-align:center;">55-63</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:center;">III</td><td style="text-align:left;">60/65/70/75/80</td><td style="text-align:center;">60-68</td><td style="text-align:left;">融災黒潮の影響あり</td></tr></tbody></table><h3 id="融災黒潮デバフ" tabindex="-1">融災黒潮デバフ <a class="header-anchor" href="#融災黒潮デバフ" aria-label="Permalink to &quot;融災黒潮デバフ&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">デバフ名</th><th style="text-align:left;">効果</th></tr></thead><tbody><tr><td style="text-align:left;">狂気衰竭</td><td style="text-align:left;">狂気獲得量を低下</td></tr><tr><td style="text-align:left;">銀鍵振盪</td><td style="text-align:left;">銀鍵エネルギーを妨害</td></tr><tr><td style="text-align:left;">怒海狂瀾</td><td style="text-align:left;">深海界域特殊効果</td></tr><tr><td style="text-align:left;">猩紅哺育</td><td style="text-align:left;">血肉界域特殊効果</td></tr><tr><td style="text-align:left;">彼界終途</td><td style="text-align:left;">超維界域特殊効果</td></tr><tr><td style="text-align:left;">来自遺忘</td><td style="text-align:left;">混沌界域特殊効果</td></tr></tbody></table><h3 id="報酬しきい値" tabindex="-1">報酬しきい値 <a class="header-anchor" href="#報酬しきい値" aria-label="Permalink to &quot;報酬しきい値&quot;">​</a></h3><p>訓練値300以上で黒色貢物x2500 + 蔷薇金券x100,000（各段階）。III級300訓練値の黒色貢物は1500から2500に引き上げられました。</p><h2 id="幻夢深潜-詳細" tabindex="-1">幻夢深潜（詳細） <a class="header-anchor" href="#幻夢深潜-詳細" aria-label="Permalink to &quot;幻夢深潜（詳細）&quot;">​</a></h2><p>Roguelikeモード。段位制（最高：幻夢伝説）。v1.5で大規模リニューアル。</p><h3 id="主なメカニクス" tabindex="-1">主なメカニクス <a class="header-anchor" href="#主なメカニクス" aria-label="Permalink to &quot;主なメカニクス&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">システム</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">マップ</td><td style="text-align:left;">戦争迷霧六角格マップ（毎日更新）。戦闘/精鋭/ボス/ショップ/休息/ランダムイベント/宝物ノード</td></tr><tr><td style="text-align:left;">刻印</td><td style="text-align:left;">通常敵撃破後に獲得（3択）。優先：妙手 &gt; 霊感 &gt; 算力 &gt; 鏡像パートナー &gt; 回想</td></tr><tr><td style="text-align:left;">造物</td><td style="text-align:left;">精鋭敵撃破後に獲得（3択、通常2負面+1正面）。銀/金/呪いの3段階</td></tr><tr><td style="text-align:left;">黒印</td><td style="text-align:left;">戦闘ドロップ。融痕（交換所）で消費。優先：造物 &gt; 覚醒 &gt; 通常刻印</td></tr></tbody></table><h3 id="深潜ショップ" tabindex="-1">深潜ショップ <a class="header-anchor" href="#深潜ショップ" aria-label="Permalink to &quot;深潜ショップ&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">アイテム</th><th style="text-align:left;">価格</th></tr></thead><tbody><tr><td style="text-align:left;">追念羽筆</td><td style="text-align:left;">融蝕之珠800=5本/週</td></tr><tr><td style="text-align:left;">碎裂余夢</td><td style="text-align:left;">融蝕之珠100/週</td></tr><tr><td style="text-align:left;">群星余夢</td><td style="text-align:left;">融蝕之珠25/週</td></tr></tbody></table><h2 id="攻略のポイント" tabindex="-1">攻略のポイント <a class="header-anchor" href="#攻略のポイント" aria-label="Permalink to &quot;攻略のポイント&quot;">​</a></h2><ol><li><strong>界域相性を確認</strong> — 各ステージのボスには有利な界域が存在</li><li><strong>ギミック対策</strong> — ステージ固有のギミックに対応した編成を組む</li><li><strong>周回効率</strong> — スタミナ効率の良いステージを優先的に周回</li><li><strong>融災禁区は複数チーム必要</strong> — 覚醒体を幅広く育成しておく</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>チャレンジステージはメインステージをある程度進めないと解放されません。まずはメインステージを進めましょう。</p></div><h2 id="報酬" tabindex="-1">報酬 <a class="header-anchor" href="#報酬" aria-label="Permalink to &quot;報酬&quot;">​</a></h2><ul><li>高レアリティ密契</li><li>高レアリティ刻印</li><li>カードLv.6強化用の特殊素材</li><li>各種育成素材（高レア）</li><li>黒色貢物・原初霊核（融災禁区）</li><li>融蝕之珠（幻夢深潜）</li></ul><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">ステージ一覧</a></li><li><a href="./../covenants/list.html">密契一覧</a></li><li><a href="./../engravings/list.html">刻印一覧</a></li><li><a href="./../cards/upgrade.html">カード強化</a></li></ul>',25)])])}const f=e(i,[["render",n]]);export{y as __pageData,f as default};
